from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    # Build a mapping of subjects to their triples
    subject_triples = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Identify the main subject (likely the monument itself)
    # Heuristic: pick the subject that appears first or has the most triples
    main_subject = triples[0].subject
    main_triples = subject_triples.get(main_subject, [])

    # Collect all information from main subject triples
    info = {}
    for triple in main_triples:
        p = triple.predicate
        o = triple.object.strip('"')
        info[p] = o

    # Collect related entity info (from other subjects that are referenced)
    related_info = {}
    for subject, subject_trips in subject_triples.items():
        if subject != main_subject:
            for triple in subject_trips:
                related_info[triple.predicate] = (subject, triple.object.strip('"'))

    # Build location chain for relative clauses
    location_parts = []
    if "location" in info:
        location_parts.append(info["location"])
    if "state" in info:
        location_parts.append(info["state"])
    if "country" in info:
        location_parts.append(info["country"])
    if "municipality" in info:
        location_parts.append(info["municipality"])

    # Build monument-specific clauses
    monument_clauses = []
    if "category" in info:
        monument_clauses.append(f"is a {info['category']}")
    if "district" in info:
        monument_clauses.append(f"is part of the district {info['district']}")
    if "established" in info:
        monument_clauses.append(f"was established on {info['established']}")
    if "foundingDate" in info:
        monument_clauses.append(f"was founded on {info['foundingDate']}")
    if "inaugurationDate" in info:
        monument_clauses.append(f"was inaugurated on {info['inaugurationDate']}")
    if "owner" in info:
        monument_clauses.append(f"is owned by {info['owner']}")
    if "owningOrganisation" in info:
        monument_clauses.append(f"is owned by {info['owningOrganisation']}")
    if "dedicatedTo" in info:
        monument_clauses.append(f"is dedicated to {info['dedicatedTo']}")
    if "designer" in info:
        monument_clauses.append(f"was designed by {info['designer']}")
    if "material" in info:
        monument_clauses.append(f"is made of {info['material']}")
    if "nativeName" in info:
        monument_clauses.append(f'native name is "{info["nativeName"]}"')

    # Build the sentence with proper structure
    parts = [main_subject]

    # Add monument clauses
    if monument_clauses:
        parts.append(", ".join(monument_clauses))

    # Add location info with relative clause
    if location_parts:
        location_str = ", ".join(location_parts)
        if len(location_parts) == 1:
            parts.append(f"which is located in {location_str}")
        else:
            parts.append(f"which is located in {location_str}")

    # Add related entity info (e.g., country capital, language, etc.)
    if "capital" in related_info:
        parts.append(f"where the capital is {related_info['capital'][1]}")
    if "language" in related_info:
        parts.append(f"where the language is {related_info['language'][1]}")
    if "ethnicGroup" in related_info:
        parts.append(f"with ethnic group {related_info['ethnicGroup'][1]}")
    if "currency" in related_info:
        parts.append(f"which uses {related_info['currency'][1]}")
    if "largestCity" in related_info:
        parts.append(f"whose largest city is {related_info['largestCity'][1]}")
    if "leader" in related_info:
        parts.append(f"led by {related_info['leader'][1]}")

    # Join all parts with appropriate conjunctions
    if len(parts) == 1:
        return f"{parts[0]}."
    elif len(parts) == 2:
        return f"{parts[0]} {parts[1]}."
    else:
        sentence = parts[0]
        for i, part in enumerate(parts[1:], 1):
            if i == 1:
                sentence += f" {part}"
            else:
                sentence += f", {part}"
        return sentence + "."

